public function renew($item, $criteria = null)
{
    if ($this->lock('refresh')) {
        try {
            $currentData = $this->driver()->get($item);
            if ($currentData !== false) {
                $updatedData = $this->applyCriteria(json_decode($currentData, true), $criteria);
                $this->driver()->set($item, json_encode($updatedData));
            }
        } finally {
            $this->unlock('refresh');
        }
    }
    return $this;
}

