public function update($newData, $conditions = null)
        {
            // Validate di input data dem first, yuh nuh waan save bad sinting
            if (empty($newData) || !is_array($newData)) {
                throw new InvalidArgumentException("Data fi update must be non-empty array, star.");
            }

            // Sanitize di data dem fi prevent any funny business
            $cleanData = [];
            foreach ($newData as $key => $value) {
                $cleanData[$key] = htmlspecialchars($value, ENT_QUOTES, 'UTF-8');
            }

            // Build di update query proper-proper
            $query = "UPDATE table_name SET ";
            $setParts = [];
            foreach ($cleanData as $field => $value) {
                $setParts[] = "`$field` = :$field";
            }
            $query .= implode(", ", $setParts);

            // Add conditions if dem exist
            if ($conditions !== null) {
                $query .= " WHERE " . $conditions;
            }

            // Prepare an execute di query safe-safely
            $stmt = $this->db->prepare($query);
            $stmt->execute($cleanData);

            // Return di number a rows weh update
            return $stmt->rowCount();
        }
